                   nccl_context->is_scaleup_nvlink,
                   sequential,
                   stream);

    // Let CPU wait
    if (with_cpu_sync)
        CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());

    // Compute stream should also wait for the barrier
    if (use_comm_stream)
        stream_wait(compute_stream, comm_stream);
}

